const __pageData = JSON.parse('{"title":"Serverless数据库：从连接池到边缘","description":"系统分析Serverless数据库的连接模型理论、连接池在FaaS环境中的形式化挑战、边缘数据库的延迟模型，并深入探讨Neon、PlanetScale、Supabase、Turso、FaunaDB、DynamoDB等主流Serverless数据库的工程实践与选型策略。","frontmatter":{"title":"Serverless数据库：从连接池到边缘","description":"系统分析Serverless数据库的连接模型理论、连接池在FaaS环境中的形式化挑战、边缘数据库的延迟模型，并深入探讨Neon、PlanetScale、Supabase、Turso、FaunaDB、DynamoDB等主流Serverless数据库的工程实践与选型策略。","date":"2026-05-01T00:00:00.000Z","tags":["数据库与ORM","Serverless","Neon","PlanetScale","Supabase","Turso","DynamoDB","边缘计算","连接池","FaaS"],"category":"engineering"},"headers":[],"relativePath":"database-orm/09-serverless-databases.md","filePath":"database-orm/09-serverless-databases.md","lastUpdated":1777741461000}');
